arguments.file_text:
# Adapter: extract a background agent's final report from a Copilot CLI
# events.jsonl and emit a Land-Verdict.ps1-compatible transcript line.
# Backfill path for #47 (producer harness silent under Copilot).
#
# Usage: python extract-copilot-report.py <events.jsonl> <toolCallId-or-substring> <task-id-label> <out.jsonl>
#
# The body is extracted VERBATIM (json-decoded, no edits). The wrapper adds only
# the <task-id>/<result> envelope Land-Verdict's Get-ResultBlockForTask matches on.
import json, sys

events_path, call_key, task_id, out_path = sys.argv[1:5]

candidates = []
for line in open(events_path, encoding='utf-8'):
    try:
        d = json.loads(line)
    except json.JSONDecodeError:
        continue
    if d.get('type') != 'tool.execution_complete':
        continue
    data = d.get('data') or {}
    if call_key not in json.dumps(data.get('toolCallId', '')) and call_key not in json.dumps(data)[:2000]:
        continue
    result = data.get('result') or {}
    content = result.get('content')
    if isinstance(content, str) and content.strip():
        candidates.append((d.get('timestamp', ''), content))

if not candidates:
    sys.exit(f'no tool.execution_complete matching {call_key!r} with string content')

candidates.sort()
ts, body = candidates[-1]
